import { cityMapping } from "./lib/cityMapping";
import AQICard from "./components/AQICard";
import { useAQIData } from "./hooks/useAQIData";

export default function Home() {
  const { data, loading, error } = useAQIData();
  const cities = Object.keys(cityMapping);

  return (
    <main className="px-4 py-10 text-center">
      <h1 className="text-3xl font-bold mb-8">Kosovo Air Quality Dashboard</h1>

      {error && <p className="text-red-600">Error fetching data</p>}

      <div className="w-full max-w-[1200px] mx-auto">
        <div className="flex flex-wrap justify-center gap-6">
          {cities.map((cityKey) => (
            <div
              key={cityKey}
              className="basis-[calc(50%-1.5rem)] md:basis-[calc(33.333%-1.5rem)] lg:basis-[calc(25%-1.5rem)] flex justify-center"
            >
              <AQICard
                city={cityMapping[cityKey]}
                data={data[cityKey]}
                loading={loading}
              />
            </div>
          ))}
        </div>
      </div>
    </main>
  );
}
